const _ioun_torch = {title: "Ioun Torch", jsx: <><h2 id="magic-wondrous-ioun_torch-ioun-torch">Ioun Torch</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_equipment">Ultimate Equipment pg. 305</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 306</Link><br/><strong>Aura</strong> strong universal; <strong>CL</strong> 12th<br/><strong>Slot</strong> none; <strong>Price</strong> 75 gp; <strong>Weight</strong> -</p>
<p>This item is merely a burned out, <Link to="/magic-ioun/dull_gray">dull gray</Link> <Link to="/magic-wondrous/ioun_stone">ioun stone</Link> with a <em>continual flame</em> spell cast upon it. It retains the ability to float and orbit, and allows the bearer to carry light and still have his hands free. It may be in any crystalline shape common to ioun stones (ellipsoid, prism, sphere, and so on).</p>
<h3 id="magic-wondrous-ioun_torch-construction">Construction</h3>
<p><strong>Requirements</strong> <Link to="/feat/craft_wondrous_item">Craft Wondrous Item</Link>, <Link to="/spell/continual_flame">continual flame</Link>, creator must be 12th level; <strong>Cost</strong> 62 gp, 5 SP</p>
</>};
